   237          @SuppressWarnings("NPathComplexity")
   238          @Override
   239          public GroupCoordinatorShard build() {
   240              if (logContext == null) logContext = new LogContext();
   241              if (config == null)
   242                  throw new IllegalArgumentException("Config must be set.");
   243              if (snapshotRegistry == null)
   244                  throw new IllegalArgumentException("SnapshotRegistry must be set.");
   245              if (time == null)
