   251              if (coordinatorMetrics == null || !(coordinatorMetrics instanceof GroupCoordinatorMetrics))
   252                  throw new IllegalArgumentException("CoordinatorMetrics must be set and be of type GroupCoordinatorMetrics.");
   253              if (topicPartition == null)
   254                  throw new IllegalArgumentException("TopicPartition must be set.");
   255              if (groupConfigManager == null)
   256                  throw new IllegalArgumentException("GroupConfigManager must be set.");
   257              if (authorizerPlugin == null)
   258                  throw new IllegalArgumentException("Authorizer must be set.");
   259
   260              GroupCoordinatorMetricsShard metricsShard = ((GroupCoordinatorMetrics) coordinatorMetrics)
   261                  .newMetricsShard(snapshotRegistry, topicPartition);
   262
   263              GroupMetadataManager groupMetadataManager = new GroupMetadataManager.Builder()
   264                  .withLogContext(logContext)
   265                  .withSnapshotRegistry(snapshotRegistry)
   266                  .withTime(time)
   267                  .withTimer(timer)
   268                  .withExecutor(executor)
   269                  .withConfig(config)
   270                  .withGroupConfigManager(groupConfigManager)
   271                  .withGroupCoordinatorMetricsShard(metricsShard)
   272                  .withShareGroupAssignor(config.shareGroupAssignors().get(0))
   273                  .withAuthorizerPlugin(authorizerPlugin)
   274                  .build();
   275
   276              OffsetMetadataManager offsetMetadataManager = new OffsetMetadataManager.Builder()
   277                  .withLogContext(logContext)
