   279                  .withTime(time)
   280                  .withGroupMetadataManager(groupMetadataManager)
   281                  .withGroupCoordinatorConfig(config)
   282                  .withGroupCoordinatorMetricsShard(metricsShard)
   283                  .build();
   284
   285              return new GroupCoordinatorShard(
   286                  logContext,
   287                  groupMetadataManager,
   288                  offsetMetadataManager,
   289                  time,
   290                  timer,
   291                  config,
   292                  coordinatorMetrics,
