  1130      /**
  1131       * Replays the Record to update the hard state of the group coordinator.
  1132       *
  1133       * @param offset        The offset of the record in the log.
  1134       * @param producerId    The producer id.
  1135       * @param producerEpoch The producer epoch.
  1136       * @param record        The record to apply to the state machine.
  1137       * @throws RuntimeException
  1138       */
  1139      @SuppressWarnings({"CyclomaticComplexity"})
  1140      @Override
  1141      public void replay(
  1142          long offset,
  1143          long producerId,
  1144          short producerEpoch,
  1145          CoordinatorRecord record
  1146      ) throws RuntimeException {
  1147          ApiMessage key = record.key();
  1148          ApiMessageAndVersion value = record.value();
  1149
  1150          CoordinatorRecordType recordType;
  1151          try {
  1152              recordType = CoordinatorRecordType.fromId(key.apiKey());
  1153          } catch (UnsupportedVersionException ex) {
  1154              throw new IllegalStateException("Received an unknown record type " + key.apiKey()
  1155                  + " in " + record, ex);
  1156          }
  1157
  1158          switch (recordType) {
  1159              case LEGACY_OFFSET_COMMIT:
  1160                  offsetMetadataManager.replay(
  1161                      offset,
  1162                      producerId,
  1163                      convertLegacyOffsetCommitKey((LegacyOffsetCommitKey) key),
  1164                      convertLegacyOffsetCommitValue((LegacyOffsetCommitValue) Utils.messageOrNull(value))
  1165                  );
  1166                  break;
  1167
  1168              case OFFSET_COMMIT:
  1169                  offsetMetadataManager.replay(
  1170                      offset,
  1171                      producerId,
  1172                      (OffsetCommitKey) key,
  1173                      (OffsetCommitValue) Utils.messageOrNull(value)
  1174                  );
  1175                  break;
  1176
  1177              case GROUP_METADATA:
  1178                  groupMetadataManager.replay(
  1179                      (GroupMetadataKey) key,
  1180                      (GroupMetadataValue) Utils.messageOrNull(value)
  1181                  );
  1182                  break;
  1183
  1184              case CONSUMER_GROUP_METADATA:
  1185                  groupMetadataManager.replay(
  1186                      (ConsumerGroupMetadataKey) key,
  1187                      (ConsumerGroupMetadataValue) Utils.messageOrNull(value)
  1188                  );
  1189                  break;
  1190
  1191              case CONSUMER_GROUP_PARTITION_METADATA:
  1192                  groupMetadataManager.replay(
  1193                      (ConsumerGroupPartitionMetadataKey) key,
  1194                      (ConsumerGroupPartitionMetadataValue) Utils.messageOrNull(value)
  1195                  );
  1196                  break;
  1197
  1198              case CONSUMER_GROUP_MEMBER_METADATA:
  1199                  groupMetadataManager.replay(
  1200                      (ConsumerGroupMemberMetadataKey) key,
  1201                      (ConsumerGroupMemberMetadataValue) Utils.messageOrNull(value)
  1202                  );
  1203                  break;
  1204
  1205              case CONSUMER_GROUP_TARGET_ASSIGNMENT_METADATA:
  1206                  groupMetadataManager.replay(
  1207                      (ConsumerGroupTargetAssignmentMetadataKey) key,
  1208                      (ConsumerGroupTargetAssignmentMetadataValue) Utils.messageOrNull(value)
  1209                  );
  1210                  break;
  1211
  1212              case CONSUMER_GROUP_TARGET_ASSIGNMENT_MEMBER:
  1213                  groupMetadataManager.replay(
  1214                      (ConsumerGroupTargetAssignmentMemberKey) key,
  1215                      (ConsumerGroupTargetAssignmentMemberValue) Utils.messageOrNull(value)
  1216                  );
  1217                  break;
  1218
  1219              case CONSUMER_GROUP_CURRENT_MEMBER_ASSIGNMENT:
  1220                  groupMetadataManager.replay(
  1221                      (ConsumerGroupCurrentMemberAssignmentKey) key,
  1222                      (ConsumerGroupCurrentMemberAssignmentValue) Utils.messageOrNull(value)
  1223                  );
  1224                  break;
  1225
  1226              case SHARE_GROUP_MEMBER_METADATA:
  1227                  groupMetadataManager.replay(
  1228                      (ShareGroupMemberMetadataKey) key,
  1229                      (ShareGroupMemberMetadataValue) Utils.messageOrNull(value)
  1230                  );
  1231                  break;
  1232
  1233              case SHARE_GROUP_METADATA:
  1234                  groupMetadataManager.replay(
  1235                      (ShareGroupMetadataKey) key,
  1236                      (ShareGroupMetadataValue) Utils.messageOrNull(value)
  1237                  );
  1238                  break;
  1239
  1240              case SHARE_GROUP_TARGET_ASSIGNMENT_METADATA:
  1241                  groupMetadataManager.replay(
  1242                      (ShareGroupTargetAssignmentMetadataKey) key,
  1243                      (ShareGroupTargetAssignmentMetadataValue) Utils.messageOrNull(value)
  1244                  );
  1245                  break;
  1246
  1247              case SHARE_GROUP_TARGET_ASSIGNMENT_MEMBER:
  1248                  groupMetadataManager.replay(
  1249                      (ShareGroupTargetAssignmentMemberKey) key,
  1250                      (ShareGroupTargetAssignmentMemberValue) Utils.messageOrNull(value)
  1251                  );
  1252                  break;
  1253
  1254              case SHARE_GROUP_CURRENT_MEMBER_ASSIGNMENT:
  1255                  groupMetadataManager.replay(
  1256                      (ShareGroupCurrentMemberAssignmentKey) key,
  1257                      (ShareGroupCurrentMemberAssignmentValue) Utils.messageOrNull(value)
  1258                  );
  1259                  break;
  1260
  1261              case SHARE_GROUP_STATE_PARTITION_METADATA:
  1262                  groupMetadataManager.replay(
  1263                      (ShareGroupStatePartitionMetadataKey) key,
  1264                      (ShareGroupStatePartitionMetadataValue) Utils.messageOrNull(value)
  1265                  );
  1266                  break;
  1267
  1268              case CONSUMER_GROUP_REGULAR_EXPRESSION:
  1269                  groupMetadataManager.replay(
  1270                      (ConsumerGroupRegularExpressionKey) key,
  1271                      (ConsumerGroupRegularExpressionValue) Utils.messageOrNull(value)
  1272                  );
  1273                  break;
  1274
  1275              case STREAMS_GROUP_METADATA:
  1276                  groupMetadataManager.replay(
  1277                      (StreamsGroupMetadataKey) key,
  1278                      (StreamsGroupMetadataValue) Utils.messageOrNull(value)
  1279                  );
  1280                  break;
  1281
  1282              case STREAMS_GROUP_MEMBER_METADATA:
  1283                  groupMetadataManager.replay(
  1284                      (StreamsGroupMemberMetadataKey) key,
  1285                      (StreamsGroupMemberMetadataValue) Utils.messageOrNull(value)
  1286                  );
  1287                  break;
  1288
  1289              case STREAMS_GROUP_TARGET_ASSIGNMENT_METADATA:
  1290                  groupMetadataManager.replay(
  1291                      (StreamsGroupTargetAssignmentMetadataKey) key,
  1292                      (StreamsGroupTargetAssignmentMetadataValue) Utils.messageOrNull(value)
  1293                  );
  1294                  break;
  1295
  1296              case STREAMS_GROUP_TARGET_ASSIGNMENT_MEMBER:
  1297                  groupMetadataManager.replay(
  1298                      (StreamsGroupTargetAssignmentMemberKey) key,
  1299                      (StreamsGroupTargetAssignmentMemberValue) Utils.messageOrNull(value)
  1300                  );
  1301                  break;
  1302
  1303              case STREAMS_GROUP_CURRENT_MEMBER_ASSIGNMENT:
  1304                  groupMetadataManager.replay(
  1305                      (StreamsGroupCurrentMemberAssignmentKey) key,
  1306                      (StreamsGroupCurrentMemberAssignmentValue) Utils.messageOrNull(value)
  1307                  );
  1308                  break;
  1309
  1310              case STREAMS_GROUP_TOPOLOGY:
  1311                  groupMetadataManager.replay(
  1312                      (StreamsGroupTopologyKey) key,
  1313                      (StreamsGroupTopologyValue) Utils.messageOrNull(value)
  1314                  );
  1315                  break;
  1316
  1317              default:
  1318                  throw new IllegalStateException("Received an unknown record type " + recordType
  1319                      + " in " + record);
  1320          }
  1321      }
