  7824      private CoordinatorResult<HeartbeatResponseData, CoordinatorRecord> classicGroupHeartbeatToConsumerGroup(
  7825          ConsumerGroup group,
  7826          AuthorizableRequestContext context,
  7827          HeartbeatRequestData request
