  7841          // 1) The group epoch is bumped so the member need to rejoin to catch up.
  7842          // 2) The member needs to revoke some partitions and rejoin to reconcile with the new epoch.
  7843          // 3) The member's partitions pending assignment are free, so it can rejoin to get the complete assignment.
  7844          if (member.memberEpoch() < group.groupEpoch() ||
  7845              member.state() == MemberState.UNREVOKED_PARTITIONS ||
  7846              (member.state() == MemberState.UNRELEASED_PARTITIONS && !group.waitingOnUnreleasedPartition(member))) {
