   657      /**
   658       * Method returns a Map keyed on groupId and value as pair of {@link DeleteShareGroupStateParameters}
   659       * and any ERRORS while building the request corresponding to the valid share groups passed as the input.
   660       * <p>
   661       * The groupIds are first filtered by type to restrict the list to share groups. If a group isn't
   662       * found or isn't a share group, it won't trigger an error in the response since group deletions
   663       * are chained. Instead, that group should be retried against other group types.
   664       * @param groupIds - A list of groupIds as string
   665       * @return A result object containing a map keyed on groupId and value pair (req, error) and related coordinator records.
   666       */
   667      public CoordinatorResult<Map<String, Map.Entry<DeleteShareGroupStateParameters, Errors>>, CoordinatorRecord> sharePartitionDeleteRequests(
   668          List<String> groupIds
   669      ) {
   670          Map<String, Map.Entry<DeleteShareGroupStateParameters, Errors>> responseMap = new HashMap<>();
   671          List<CoordinatorRecord> records = new ArrayList<>();
   672          for (String groupId : groupIds) {
   673              try {
   674                  ShareGroup group = groupMetadataManager.shareGroup(groupId);
   675                  group.validateDeleteGroup();
   676                  groupMetadataManager.shareGroupBuildPartitionDeleteRequest(groupId, records)
   677                      .ifPresent(req -> responseMap.put(groupId, Map.entry(req, Errors.NONE)));
   678              } catch (GroupIdNotFoundException exception) {
   679                  log.debug("Unable to delete share group. GroupId {} not found.", groupId);
   680                  // Do not include the error in response map, as the deletion of groups is chained hence
   681                  // the respective group should be re-tried for deletion against other group types.
   682              } catch (GroupNotEmptyException exception) {
   683                  log.debug("Unable to delete share group. Provided group {} is not empty.", groupId);
   684                  responseMap.put(groupId, Map.entry(DeleteShareGroupStateParameters.EMPTY_PARAMS, Errors.forException(exception)));
   685              }
   686          }
   687          return new CoordinatorResult<>(records, responseMap);
   688      }
