  1247                          // We always keep the most recent committed offset when we have a mix of transactional and regular
  1248                          // offset commits. Without preserving information of the commit record offset, compaction of the
  1249                          // __consumer_offsets topic itself may result in the wrong offset commit being materialized.
  1250                          if (existingOffsetAndMetadata == null || offsetAndMetadata.recordOffset > existingOffsetAndMetadata.recordOffset) {
