  1252                                  "with topic {} and partition {}.",
  1253                                  offsetAndMetadata, producerId, groupId, topicName, partitionId);
  1254                              OffsetAndMetadata previousValue = offsets.put(
  1255                                  groupId,
  1256                                  topicName,
  1257                                  partitionId,
  1258                                  offsetAndMetadata
  1259                              );
  1260                              if (previousValue == null) {
