1141      public void replay(
  1142          long recordOffset,
  1143          long producerId,
  1144          OffsetCommitKey key,
  1145          OffsetCommitValue value
  1146      ) {
  1147          final String groupId = key.group();
  1148          final String topic = key.topic();
  1149          final int partition = key.partition();
  1150
  1151          if (value != null) {
  1152              // The classic or consumer group should exist when offsets are committed or
  1153              // replayed. However, it won't if the consumer commits offsets but does not
  1154              // use the membership functionality. In this case, we automatically create
  1155              // a so-called "simple consumer group". This is an empty classic group
  1156              // without a protocol type.
  1157              try {
  1158                  groupMetadataManager.group(groupId);
  1159              } catch (GroupIdNotFoundException ex) {
  1160                  groupMetadataManager.getOrMaybeCreateClassicGroup(groupId, true);
  1161              }
  1162
  1163              if (producerId == RecordBatch.NO_PRODUCER_ID) {
  1164                  log.debug("Replaying offset commit with key {}, value {}", key, value);
  1165                  // If the offset is not part of a transaction, it is directly stored
  1166                  // in the offsets store.
  1167                  OffsetAndMetadata previousValue = offsets.put(
  1168                      groupId,
  1169                      topic,
  1170                      partition,
  1171                      OffsetAndMetadata.fromRecord(recordOffset, value)
  1172                  );
  1173                  if (previousValue == null) {
  1174                      metrics.incrementNumOffsets();
  1175                  }
  1176              } else {
  1177                  log.debug("Replaying transactional offset commit with producer id {}, key {}, value {}", producerId, key, value);
  1178                  // Otherwise, the transaction offset is stored in the pending transactional
  1179                  // offsets store. Pending offsets there are moved to the main store when
  1180                  // the transaction is committed; or removed when the transaction is aborted.
  1181                  pendingTransactionalOffsets
  1182                      .computeIfAbsent(producerId, __ -> new Offsets())
  1183                      .put(
  1184                          groupId,
  1185                          topic,
  1186                          partition,
  1187                          OffsetAndMetadata.fromRecord(recordOffset, value)
  1188                      );
  1189                  openTransactions.add(groupId, topic, partition, producerId);
  1190              }
  1191          } else {
  1192              if (offsets.remove(groupId, topic, partition) != null) {
  1193                  metrics.decrementNumOffsets();
  1194              }
  1195
  1196              // Remove all the pending offset commits related to the tombstone.
  1197              openTransactions.forEach(groupId, topic, partition, openProducerId -> {
  1198                  Offsets pendingOffsets = pendingTransactionalOffsets.get(openProducerId);
  1199                  if (pendingOffsets != null) {
  1200                      pendingOffsets.remove(groupId, topic, partition);
  1201                  }
  1202              });
  1203              openTransactions.clear(groupId, topic, partition);
  1204          }
  1205      }
