   954          if (protocolType.isPresent()) {
   955              if (isInState(EMPTY)) {
   956                  // No members exist in the group =>
   957                  // - If current state timestamp exists and retention period has passed since group became Empty,
   958                  //   expire all offsets with no pending offset commit;
   959                  // - If there is no current state timestamp (old group metadata schema) and retention period has passed
   960                  //   since the last commit timestamp, expire the offset
   961                  return Optional.of(new OffsetExpirationConditionImpl(
   962                      offsetAndMetadata -> currentStateTimestamp.orElse(offsetAndMetadata.commitTimestampMs))
   963                  );
   964              } else if (usesConsumerGroupProtocol() && subscribedTopics.isPresent() && isInState(STABLE)) {
   965                  // Consumers exist in the group and group is Stable =>
   966                  // - If the group is aware of the subscribed topics and retention period has passed since the
   967                  //   last commit timestamp, expire the offset.
   968                  return Optional.of(new OffsetExpirationConditionImpl(offsetAndMetadata -> offsetAndMetadata.commitTimestampMs));
   969              }
   970          } else {
   971              // protocolType is None => standalone (simple) consumer, that uses Kafka for offset storage. Only
   972              // expire offsets where retention period has passed since their last commit.
   973              return Optional.of(new OffsetExpirationConditionImpl(offsetAndMetadata -> offsetAndMetadata.commitTimestampMs));
   974          }
   975          // If none of the conditions above are met, do not expire any offsets.

975          // If none of the conditions above are met, do not expire any offsets.
   976          return Optional.empty();
