  1047          long currentTimestampMs = time.milliseconds();
  1048          Optional<OffsetExpirationCondition> offsetExpirationCondition = group.offsetExpirationCondition();
  1049
  1050          if (offsetExpirationCondition.isEmpty()) {
  1051              return false;
  1052          }
  1053
  1054          AtomicBoolean allOffsetsExpired = new AtomicBoolean(true);
  1055          OffsetExpirationCondition condition = offsetExpirationCondition.get();
  1056
  1057          offsetsByTopic.forEach((topic, partitions) -> {
  1058              if (!group.isSubscribedToTopic(topic)) {
  1059                  partitions.forEach((partition, offsetAndMetadata) -> {
  1060                      // We don't expire the offset yet if there is a pending transactional offset for the partition.
  1061                      if (condition.isOffsetExpired(offsetAndMetadata, currentTimestampMs, config.offsetsRetentionMs()) &&
  1062                          !hasPendingTransactionalOffsets(groupId, topic, partition)) {
  1063                          appendOffsetCommitTombstone(groupId, topic, partition, records);
  1064                          log.debug("[GroupId {}] Expired offset for partition={}-{}", groupId, topic, partition);
  1065                      } else {
  1066                          allOffsetsExpired.set(false);
  1067                      }
  1068                  });
  1069              } else {
  1070                  allOffsetsExpired.set(false);
  1071              }
  1072          });
  1073          metrics.record(OFFSET_EXPIRED_SENSOR_NAME, records.size());
  1074
  1075          // We don't want to remove the group if there are ongoing transactions with undeleted offsets.
  1076          return allOffsetsExpired.get() && !openTransactions.contains(groupId);
