  1090          Consumer<Offsets> delete = offsetsToClean -> {
  1091              offsetsToClean.offsetsByGroup.forEach((groupId, topicOffsets) -> {
  1092                  for (DeletedTopic deletedTopic : deletedTopics) {
  1093                      var partitionOffsets = topicOffsets.get(deletedTopic.name());
  1094                      if (partitionOffsets != null) {
  1095                          partitionOffsets.forEach((partition, offsetAndMetadata) -> {
  1096                              // Delete if the topic ID matches or if the stored topic ID is ZERO_UUID (legacy records).
  1097                              if (offsetAndMetadata.topicId.equals(Uuid.ZERO_UUID) || offsetAndMetadata.topicId.equals(deletedTopic.id())) {
  1098                                  appendOffsetCommitTombstone(groupId, deletedTopic.name(), partition, records);
  1099                              }
  1100                          });
  1101                      }
  1102                  }
  1103              });
  1104          };
  1105
  1106          // Delete the offsets from the main storage.
  1107          delete.accept(offsets);
  1108          // Delete the offsets from the pending transactional offsets.
  1109          pendingTransactionalOffsets.forEach((__, offsets) -> delete.accept(offsets));
  1110
  1111          return records;
