@Test
public void testCleanupGroupMetadataPartialExpiryDoesNotDeleteGroup() {
    GroupMetadataManager groupMetadataManager = mock(GroupMetadataManager.class);
    OffsetMetadataManager offsetMetadataManager = mock(OffsetMetadataManager.class);
    MockTime mockTime = new MockTime();
    GroupCoordinatorShard coordinator = new GroupCoordinatorShard(
        new LogContext(), groupMetadataManager, offsetMetadataManager,
        mockTime, new MockCoordinatorTimer<>(mockTime),
        mock(GroupCoordinatorConfig.class), mock(CoordinatorMetrics.class),
        mock(CoordinatorMetricsShard.class)
    );

    SnapshotRegistry snapshotRegistry = new SnapshotRegistry(new LogContext());
    ConsumerGroup groupA = new ConsumerGroup(new LogContext(), snapshotRegistry, "group-a");
    ConsumerGroup groupB = new ConsumerGroup(new LogContext(), snapshotRegistry, "group-b");

    CoordinatorRecord partialTombstone =
        GroupCoordinatorRecordHelpers.newOffsetCommitTombstoneRecord("group-b", "topic", 3);

    when(groupMetadataManager.groupIds()).thenReturn(Set.of("group-a", "group-b"));
    when(groupMetadataManager.group("group-a")).thenReturn(groupA);
    when(groupMetadataManager.group("group-b")).thenReturn(groupB);
    // group-a: all offsets expired
    when(offsetMetadataManager.cleanupExpiredOffsets(eq("group-a"), anyList())).thenReturn(true);
    // group-b: only some offsets expired — add one tombstone but return false
    when(offsetMetadataManager.cleanupExpiredOffsets(eq("group-b"), anyList()))
        .thenAnswer(inv -> {
            inv.<List<CoordinatorRecord>>getArgument(1).add(partialTombstone);
            return false;
        });

    CoordinatorResult<Void, CoordinatorRecord> result = coordinator.cleanupGroupMetadata();

    // group-a's maybeDeleteGroup called; group-b's MUST NOT be called
    verify(groupMetadataManager, times(1)).maybeDeleteGroup(eq("group-a"), anyList());
    verify(groupMetadataManager, never()).maybeDeleteGroup(eq("group-b"), anyList());
    // The partial tombstone from group-b IS present in the result
    assertTrue(result.records().contains(partialTombstone),
        "Partial offset tombstone should be included in coordinator result records");
}
```

